SELECT neuron_id
FROM neurons
WHERE convergence > 0.5;

SELECT neuron_id, AVG(convergence) as average_convergence
FROM neurons
GROUP BY neuron_id;

SELECT neuron_id, MAX(divergence) AS max_divergence
FROM neurons
WHERE recording_date = '2023-06-15';

SELECT neuron_id, intercept, AVG(convergence) OVER () AS average_convergence
FROM neurons
WHERE convergence > 0.5;

SELECT neuron_id, convergence
FROM neurons
WHERE convergence > (SELECT AVG(convergence) FROM neurons);

SELECT analysis_type
FROM data_analysis
WHERE analysis_id = 1;
